export const Schema = z.object({
    世界: z.object({
        当前时间: z.string(),
        当前地点: z.string(),
        天气: z.string(),
        威胁等级: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
        近期事务: z.record(z.string().describe('事务名'), z.string().describe('事务描述')),
    }),
    主角: z.object({
        生存: z.object({
            生命: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            饥饿: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            体力: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            感染: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
        }),
        物品栏: z
            .record(z.string().describe('物品名'), z.object({
            描述: z.string(),
            数量: z.coerce.number(),
        }))
            .transform(data => _.pickBy(data, ({ 数量 }) => 数量 > 0)),
    }),
});
